class Solution:
    def removeDuplicates(self, s):
        cur = s
        while True:
            nxt = None
            for i in range(len(cur) - 1):
                if cur[i] == cur[i + 1]:
                    nxt = cur[:i] + cur[i + 2:]
                    break
            if nxt is None:
                return cur
            cur = nxt

solutions.python:
class Solution:
    def removeDuplicates(self, s):
        stack = []
        for c in s:
            if stack and stack[-1] == c:
                stack.pop()
            else:
                stack.append(c)
        return ''.join(stack)

